79	// Reasoning handling mode (derived from R1-R3 comparisons)
80	enum class reasoning_mode {
81	    NONE,           // No reasoning markers detected
82	    TAG_BASED,      // Tag-based: <think>...</think> (start can be empty for delimiter-style)
83	    TOOLS_ONLY      // Only reason on tool calls, not on normal content
84	};
85	
86	inline std::ostream & operator<<(std::ostream & os, const reasoning_mode & mode) {
87	    switch (mode) {
88	        case reasoning_mode::NONE:
89	            return os << "NONE";
90	        case reasoning_mode::TAG_BASED:
91	            return os << "TAG_BASED";
92	        case reasoning_mode::TOOLS_ONLY:
93	            return os << "TOOLS_ONLY";
94	        default:
95	            return os << "UNKNOWN";
96	    }
97	}
98	
99	// Content wrapping mode (derived from C1 comparison)
100	enum class content_mode {
101	    PLAIN,                   // No content markers
102	    ALWAYS_WRAPPED,          // Content always wrapped with markers
103	    WRAPPED_WITH_REASONING,  // Content wrapped only when reasoning present
104	};
105	
106	inline std::ostream & operator<<(std::ostream & os, const content_mode & mode) {
107	    switch (mode) {
108	        case content_mode::PLAIN:
109	            return os << "PLAIN";
110	        case content_mode::ALWAYS_WRAPPED:
111	            return os << "ALWAYS_WRAPPED";
112	        case content_mode::WRAPPED_WITH_REASONING:
113	            return os << "WRAPPED_WITH_REASONING";
114	        default:
115	            return os << "UNKNOWN";
116	    }
117	}
118	
119	// Call ID position in tool calls (for non-JSON formats)
120	enum class call_id_position {
121	    NONE,                   // No call ID support detected
122	    PRE_FUNC_NAME,          // Call ID before function name: [CALL_ID]id[FUNC]name{args}
123	    BETWEEN_FUNC_AND_ARGS,  // Call ID between function and args: [FUNC]name[CALL_ID]id{args}
124	    POST_ARGS,              // Call ID after arguments: [FUNC]name{args}[CALL_ID]id
125	};
126	
127	inline std::ostream & operator<<(std::ostream & os, const call_id_position & pos) {
128	    switch (pos) {
129	        case call_id_position::NONE:
130	            return os << "NONE";
131	        case call_id_position::PRE_FUNC_NAME:
132	            return os << "PRE_FUNC_NAME";
133	        case call_id_position::BETWEEN_FUNC_AND_ARGS:
134	            return os << "BETWEEN_FUNC_AND_ARGS";
135	        case call_id_position::POST_ARGS:
136	            return os << "POST_ARGS";
137	        default:
138	            return os << "UNKNOWN";
139	    }
140	}
141	
142	// Tool call format classification (derived from T1-T5, A1-A3 comparisons)
143	enum class tool_format {
144	    NONE,             // No tool support detected
145	    JSON_NATIVE,      // Pure JSON: {"name": "X", "arguments": {...}}
146	    TAG_WITH_JSON,    // Tag-based with JSON args: <function=X>{...}</function>
147	    TAG_WITH_TAGGED,  // Tag-based with tagged args: <param=key>value</param>
148	    TAG_WITH_GEMMA4_DICT, // Gemma4 custom dict: <|tool_call>call:name{key:<|"|>val<|"|>}<tool_call|>
149	};
150	
151	inline std::ostream & operator<<(std::ostream & os, const tool_format & format) {
152	    switch (format) {
153	        case tool_format::NONE:
154	            return os << "NONE";
155	        case tool_format::JSON_NATIVE:
156	            return os << "JSON_NATIVE";
157	        case tool_format::TAG_WITH_JSON:
158	            return os << "TAG_WITH_JSON";
159	        case tool_format::TAG_WITH_TAGGED:
160	            return os << "TAG_WITH_TAGGED";
161	        case tool_format::TAG_WITH_GEMMA4_DICT:
162	            return os << "TAG_WITH_GEMMA4_DICT";
163	        default:
164	            return os << "UNKNOWN";
165	    }
166	}
