243	void autoparser::collect_preserved_tokens() {
244	    auto add_token = [this](const std::string & org_token) {
245	        std::string token = trim_whitespace(org_token);
246	        if (!token.empty()) {
247	            // Avoid duplicates
248	            if (std::find(preserved_tokens.begin(), preserved_tokens.end(), token) == preserved_tokens.end()) {
249	                preserved_tokens.push_back(token);
250	            }
251	        }
252	    };
253	
254	    add_token(reasoning.start);
255	    add_token(reasoning.end);
256	    add_token(content.start);
257	    add_token(content.end);
258	    add_token(tools.format.section_start);
259	    add_token(tools.format.section_end);
260	    add_token(tools.format.per_call_start);
261	    add_token(tools.format.per_call_end);
262	    add_token(tools.function.name_prefix);
263	    add_token(tools.function.name_suffix);
264	    add_token(tools.function.close);
265	    add_token(tools.arguments.start);
266	    add_token(tools.arguments.end);
267	    add_token(tools.arguments.name_prefix);
268	    add_token(tools.arguments.name_suffix);
269	    add_token(tools.arguments.separator);
270	    add_token(tools.arguments.value_prefix);
271	    add_token(tools.arguments.value_suffix);
272	    add_token(tools.call_id.prefix);
273	    add_token(tools.call_id.suffix);
274	}
