608	void analyze_tools::analyze_tool_calls(const analyze_reasoning & reasoning) {
609	    json assistant_no_tools = json{
610	        { "role",    "assistant"   },
611	        { "content", ASSISTANT_MSG }
612	    };
613	
614	    json assistant_with_tools = json{
615	        { "role",       "assistant"                      },
616	        { "content",    ""                               },
617	        { "tool_calls", json::array({ first_tool_call }) }
618	    };
619	
620	    template_params params;
621	    params.messages              = json::array({ user_msg, assistant_no_tools });
622	    params.tools                 = tools;
623	    params.add_generation_prompt = false;
624	    params.enable_thinking       = true;
625	
626	    auto comparison = compare_variants(
627	        *tmpl, params, [&](template_params & p) { p.messages = json::array({ user_msg, assistant_with_tools }); });
628	
629	    if (!comparison) {
630	        LOG_DBG(ANSI_ORANGE "%s: Template application failed\n" ANSI_RESET, __func__);
631	        return;
632	    }
633	
634	    const auto & diff = comparison->diff;
635	
636	    std::string tool_section = diff.right;
637	
638	    if (tool_section.empty()) {
639	        return;
640	    }
641	
642	    analyze_tool_call_format(tool_section, FUN_FIRST, ARG_FIRST, reasoning);
643	}
