645	void analyze_tools::analyze_tool_call_format(const std::string &       haystack,
646	                                             const std::string &       fun_name_needle,
647	                                             const std::string &       arg_name_needle,
648	                                             const analyze_reasoning & reasoning) {
649	    if (fun_name_needle.empty() || arg_name_needle.empty() || haystack.empty()) {
650	        return;
651	    }
652	
653	    auto in_json_haystack = [&haystack](const std::string & needle) -> bool {
654	        auto parser = build_tagged_peg_parser([&](common_peg_parser_builder &p) {
655	            return p.choice({ p.literal("{"), p.literal(":") }) << p.choice({
656	                p.tag("dq", p.literal("\"") + p.literal(needle) + p.literal("\"")) });
657	        });
658	        auto result = parser.parse_anywhere_and_extract(haystack);
659	        return result.result.success();
660	    };
661	
662	    auto fun_quote = in_json_haystack(fun_name_needle);
663	    auto arg_quote = in_json_haystack(arg_name_needle);
664	
665	    if (fun_quote) {
666	        // no need to check further, we're in JSON land
667	        format.mode = tool_format::JSON_NATIVE;
668	    } else if (arg_quote) {
669	        format.mode = tool_format::TAG_WITH_JSON;
670	    } else {
671	        format.mode = tool_format::TAG_WITH_TAGGED;
672	    }
673	
674	    // first, remove any reasoning markers
675	    std::string clean_haystack = haystack;
676	    if (!reasoning.start.empty()) {
677	        auto pos = haystack.find(reasoning.start);
678	        if (pos != std::string::npos) {
679	            clean_haystack = haystack.substr(0, pos) + haystack.substr(pos + reasoning.start.length());
680	        }
681	    }
682	    if (!reasoning.end.empty()) {
683	        auto pos = clean_haystack.find(reasoning.end);
684	        if (pos != std::string::npos) {
685	            clean_haystack = clean_haystack.substr(0, pos) + clean_haystack.substr(pos + reasoning.end.length());
686	        }
687	    }
688	
689	    if (format.mode == tool_format::JSON_NATIVE) {
690	        analyze_tool_call_format_json_native(clean_haystack, fun_name_needle, arg_name_needle);
691	    } else {
692	        analyze_tool_call_format_non_json(clean_haystack, fun_name_needle);
693	    }
694	    // always relax whitespace requirements on ending markers since they don't influence content
695	    format.section_end  = trim_whitespace(format.section_end);
696	    format.per_call_end = trim_whitespace(format.per_call_end);
697	}
