```cpp
void analyze_tools::analyze_tool_call_format(
    const std::string & haystack,  // Extracted tool section
    const std::string & fun_name_needle,  // e.g., "tool_choice_first"
    const std::string & arg_name_needle,  // e.g., "param_first"
    const analyze_reasoning & reasoning) {

    // Check if JSON format (look for quotes around function name)
    auto in_json_haystack = [&haystack](const std::string & needle) -> bool {
        // PEG parser to find "{" or ":" followed by quoted needle
        auto parser = build_tagged_peg_parser([&](common_peg_parser_builder &p) {
            return p.choice({ p.literal("{"), p.literal(":") }) << 
                   p.tag("dq", p.literal("\"") + p.literal(needle) + p.literal("\""));
        });
        return parser.parse_anywhere_and_extract(haystack).result.success();
    };

    if (in_json_haystack(fun_name_needle)) {
        format.mode = tool_format::JSON_NATIVE;  // Pure JSON format
    } else if (in_json_haystack(arg_name_needle)) {
        format.mode = tool_format::TAG_WITH_JSON;  // Tags + JSON args
    } else {
        format.mode = tool_format::TAG_WITH_TAGGED;  // All tags, no JSON
    }
}
```

**Four Tool Format Types Detected**:
- `JSON_NATIVE`: Pure JSON (e.g., OpenAI format)
- `TAG_WITH_JSON`: Tags for structure, JSON for arguments (e.g., `<function=foo>{...}</function>`)
- `TAG_WITH_TAGGED`: All markers are tags (e.g., `<function=foo><arg=bar>value</arg></function>`)
- `TAG_WITH_GEMMA4_DICT`: Gemma4's custom dict format

